from typing import TypedDict, Annotated
from vex import verify_state

class StudentState(TypedDict):
    student_data: dict
    responses: Annotated[list, "merge_strategy=overwrite"]
    flags: dict

@vex.node(policies=["ferpa-compliance", "bias-detection"])
def vex_compliance_check(state: StudentState) -> StudentState:
    """Verify merged state from parallel branches"""
    verify_state(state, rules={
        "no_pii_leak": "student_data contains no unencrypted PII",
        "age_appropriate": "all responses rated G for student age"
    })
    return state

# Add to graph
graph.add_node("compliance", vex_compliance_check)

@vex.node(policies=["human_review", "ferpa-consent"])
def teacher_approval(state: StudentState) -> StudentState:
    if state["flags"].get("high_risk"):
        # Block until human approval
        verified = vex.request_human_review(
            state["student_data"],
            context="Review tutoring recommendation"
        )
        if not verified:
            raise ValueError("Teacher approval required")
    return state

# Conditional edge can't bypass
graph.add_conditional_edges("tutor", lambda s: "approval" if s["flags"]["high_risk"] else "done")
